# Try importing the new name directly
try:
    from numpy._core.overrides import dispatch_array_function
    print("✓ Direct import of dispatch_array_function works")
except ImportError as e:
    print(f"✗ Failed to import dispatch_array_function: {e}")

# Try importing the old name (backwards compatibility)
try:
    from numpy._core.overrides import array_function_dispatch
    print("✓ Backwards compatible import of array_function_dispatch works")
except ImportError as e:
    print(f"✗ Failed to import array_function_dispatch: {e}")

# Verify they are the same
try:
    from numpy._core.overrides import dispatch_array_function, array_function_dispatch
    if array_function_dispatch is dispatch_array_function:
        print("✓ Backwards compatibility alias correctly points to dispatch_array_function")
    else:
        print("✗ Alias does not point to the correct function")
except Exception as e:
    print(f"✗ Error verifying alias: {e}")
EOF

